\\\\\": [],\\\\n      \\\\\\\"page_end\\\\\\\": 2,\\\\n      \\\\\\\"need_review_reason\\\\\\\": \\\\\\\"\\\\\\\",\\\\n      \\\\\\\"raw_explanation\\\\\\\": \\\\\\\"【详解】因为 $\\\\\\\\\\\\\\\\frac{z}{z-1}=\\\\\\\\\\\\\\\\frac{z-1+1}{z-1}=1+\\\\\\\\\\\\\\\\frac{1}{z-1}=1+i$，所以 $\\\\\\\\\\\\\\\\frac{1}{z-1}=i$，即 $z-1=\\\\\\\\\\\\\\\\frac{1}{i}=-i$，故 $z=1-i$.\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"question_no\\\\\\\": \\\\\\\"3\\\\\\\",\\\\n      \\\\\\\"section_title\\\\\\\": \\\\\\\"一、选择题\\\\\\\",\\\\n      \\\\\\\"question_type\\\\\\\": \\\\\\\"single_choice\\\\\\\",\\\\n      \\\\\\\"stem\\\\\\\": \\\\\\\"已知向量 $\\\\\\\\\\\\\\\\vec{a} = (0, 1)$，$\\\\\\\\\\\\\\\\vec{b} = (2, x)$，若 $\\\\\\\\\\\\\\\\vec{b} \\\\\\\\\\\\\\\\perp (\\\\\\\\\\\\\\\\vec{b} - 4\\\\\\\\\\\\\\\\vec{a})$，则 $x =$（ ）\\\\\\\",\\\\n      \\\\\\\"options\\\\\\\": [\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"A\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$-2$\\\\\\\", \\\\\\\"bbox\\\\\\\": [88, 558, 138, 575]},\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"B\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$-1$\\\\\\\", \\\\\\\"bbox\\\\\\\": [292, 558, 335, 575]},\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"C\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$1$\\\\\\\", \\\\\\\"bbox\\\\\\\": [497, 558, 532, 575]},\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"D\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$2$\\\\\\\", \\\\\\\"bbox\\\\\\\": [701, 558, 738, 575]}\\\\n      ],\\\\n      \\\\\\\"answer\\\\\\\": \\\\\\\"D\\\\\\\",\\\\n      \\\\\\\"analysis\\\\\\\": \\\\\\\"根据向量垂直的坐标运算可求 $x$ 的值.\\\\\\\",\\\\n      \\\\\\\"solution\\\\\\\": \\\\\\\"因为 $\\\\\\\\\\\\\\\\vec{b} \\\\\\\\\\\\\\\\perp (\\\\\\\\\\\\\\\\vec{b} - 4\\\\\\\\\\\\\\\\vec{a})$，所以 $\\\\\\\\\\\\\\\\vec{b} \\\\\\\\\\\\\\\\cdot (\\\\\\\\\\\\\\\\vec{b} - 4\\\\\\\\\\\\\\\\vec{a}) = 0$，即 $\\\\\\\\\\\\\\\\vec{b}^2 - 4\\\\\\\\\\\\\\\\vec{a} \\\\\\\\\\\\\\\\cdot \\\\\\\\\\\\\\\\vec{b} = 0$。计算得：$\\\\\\\\\\\\\\\\vec{b}^2 = 2^2 + x^2 = 4 + x^2$，$\\\\\\\\\\\\\\\\vec{a} \\\\\\\\\\\\\\\\cdot \\\\\\\\\\\\\\\\vec{b} = 0 \\\\\\\\\\\\\\\\cdot 2 + 1 \\\\\\\\\\\\\\\\cdot x = x$，代入得 $4 + x^2 - 4x = 0$，即 $(x - 2)^2 = 0$，故 $x = 2$.\\\\\\\",\\\\n      \\\\\\\"comment\\\\\\\": \\\\\\\"\\\\\\\",\\\\n      \\\\\\\"knowledge_points\\\\\\\": [\\\\\\\"向量垂直的充要条件\\\\\\\", \\\\\\\"向量点积运算\\\\\\\"],\\\\n      \\\\\\\"difficulty\\\\\\\": 3,\\\\n      \\\\\\\"bbox\\\\\\\": [87, 512, 740, 575],\\\\n      \\\\\\\"region_json\\\\\\\": {\\\\\\\"x1\\\\\\\": 87, \\\\\\\"y1\\\\\\\": 512, \\\\\\\"x2\\\\\\\": 740, \\\\\\\"y2\\\\\\\": 575},\\\\n      \\\\\\\"confidence\\\\\\\": 0.99,\\\\n      \\\\\\\"images\\\\\\\": [],\\\\n      \\\\\\\"page_end\\\\\\\": 2,\\\\n      \\\\\\\"need_review_reason\\\\\\\": \\\\\\\"\\\\\\\",\\\\n      \\\\\\\"raw_explanation\\\\\\\": \\\\\\\"【详解】因为 $\\\\\\\\\\\\\\\\vec{b} \\\\\\\\\\\\\\\\perp (\\\\\\\\\\\\\\\\vec{b} - 4\\\\\\\\\\\\\\\\vec{a})$，所以 $\\\\\\\\\\\\\\\\vec{b} \\\\\\\\\\\\\\\\cdot (\\\\\\\\\\\\\\\\vec{b} - 4\\\\\\\\\\\\\\\\vec{a}) = 0$，所以 $\\\\\\\\\\\\\\\\vec{b}^2 - 4\\\\\\\\\\\\\\\\vec{a} \\\\\\\\\\\\\\\\cdot \\\\\\\\\\\\\\\\vec{b} = 0$ 即 $4 + x^2 - 4x = 0$，故 $x = 2$.\\\\\\\"\\\\n    },\\\\n    {\\\\n      \\\\\\\"question_no\\\\\\\": \\\\\\\"4\\\\\\\",\\\\n      \\\\\\\"section_title\\\\\\\": \\\\\\\"一、选择题\\\\\\\",\\\\n      \\\\\\\"question_type\\\\\\\": \\\\\\\"single_choice\\\\\\\",\\\\n      \\\\\\\"stem\\\\\\\": \\\\\\\"已知 $\\\\\\\\\\\\\\\\cos(\\\\\\\\\\\\\\\\alpha + \\\\\\\\\\\\\\\\beta) = m$，$\\\\\\\\\\\\\\\\tan\\\\\\\\\\\\\\\\alpha \\\\\\\\\\\\\\\\tan\\\\\\\\\\\\\\\\beta = 2$，则 $\\\\\\\\\\\\\\\\cos(\\\\\\\\\\\\\\\\alpha - \\\\\\\\\\\\\\\\beta) =$（ ）\\\\\\\",\\\\n      \\\\\\\"options\\\\\\\": [\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"A\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$-3m$\\\\\\\", \\\\\\\"bbox\\\\\\\": [88, 848, 155, 865]},\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"B\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$-\\\\\\\\\\\\\\\\frac{m}{3}$\\\\\\\", \\\\\\\"bbox\\\\\\\": [292, 832, 355, 865]},\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"C\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$\\\\\\\\\\\\\\\\frac{m}{3}$\\\\\\\", \\\\\\\"bbox\\\\\\\": [497, 832, 543, 865]},\\\\n        {\\\\\\\"label\\\\\\\": \\\\\\\"D\\\\\\\", \\\\\\\"content\\\\\\\": \\\\\\\"$3m$\\\\\\\", \\\\\\\"bbox\\\\\\\": [701, 848, 757, 865]}\\\\n      ],\\\\n      \\\\\\\"answer\\\\\\\": \\\\\\\"A\\\\\\\",\\\\n      \\\\\\\"analysis\\\\\\\": \\\\\\\"\\\\\\\",\\\\n      \\\\\\\"solution\\\\\\\": \\\\\\\"利用余弦和差公式：\\\\\\\\n$$\\\\\\\\n\\\\\\\\\\\\\\\\cos(\\\\\\\\\\\\\\\\alpha + \\\\\\\\\\\\\\\\beta) = \\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\beta - \\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\beta = m,\\\\\\\\n$$\\\\\\\\n$$\\\\\\\\n\\\\\\\\\\\\\\\\cos(\\\\\\\\\\\\\\\\alpha - \\\\\\\\\\\\\\\\beta) = \\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\beta + \\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\beta.\\\\\\\\n$$\\\\\\\\n又 $\\\\\\\\\\\\\\\\tan\\\\\\\\\\\\\\\\alpha \\\\\\\\\\\\\\\\tan\\\\\\\\\\\\\\\\beta = \\\\\\\\\\\\\\\\frac{\\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\beta}{\\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\beta} = 2$，设 $\\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\cos\\\\\\\\\\\\\\\\beta = t$，则 $\\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\alpha\\\\\\\\\\\\\\\\sin\\\\\\\\\\\\\\\\beta = 2t$。\\\\\\\\n\\\\\\\\n代入得：$t - 2t = m \\\\\\\\\\\\\\\\Rightarrow -t = m \\\\\\\\\\\\\\\\Rightarrow t = -m$，\\\\\\\\n\\\\\\\\n所以 $\\\\\\\\\\\\\\\\cos(\\\\\\\\\\\\\\\\alpha - \\\\\\\\\\\\\\\\beta) = t + 2t = 3t = -3m$.\\\\\\\",\\\\n      \\\\\\\"comment\\\\\\\": \\\\\\\"\\\\\\\",\\\\n      \\\\\\\"knowledge_points\\\\\\\": [\\\\\\\"三角恒等变换\\\\\\\", \\\\\\\"余弦和差公式\\\\\\\", \\\\\\\"正切与正余弦关系\\\\\\\"],\\\\n      \\\\\\\"difficulty\\\\\\\": 4,\\\\n      \\\\\\\"bbox\\\\\\\": [87, 782, 757, 865],\\\\n      \\\\\\\"region_json\\\\\\\": {