\n    {\n      \"question_no\": \"4\",\n      \"section_title\": \"一、选择题\",\n      \"question_type\": \"single_choice\",\n      \"stem\": \"已知 $\\\\cos(\\\\alpha + \\\\beta) = m$，$\\\\tan\\\\alpha \\\\tan\\\\beta = 2$，则 $\\\\cos(\\\\alpha - \\\\beta) =$（ ）\",\n      \"options\": [\n        {\"label\": \"A\", \"content\": \"$-3m$\", \"bbox\": [88, 848, 155, 865]},\n        {\"label\": \"B\", \"content\": \"$-\\\\frac{m}{3}$\", \"bbox\": [292, 832, 355, 865]},\n        {\"label\": \"C\", \"content\": \"$\\\\frac{m}{3}$\", \"bbox\": [497, 832, 543, 865]},\n        {\"label\": \"D\", \"content\": \"$3m$\", \"bbox\": [701, 848, 757, 865]}\n      ],\n      \"answer\": \"A\",\n      \"analysis\": \"\",\n      \"solution\": \"利用余弦和差公式：\\n$$\\n\\\\cos(\\\\alpha + \\\\beta) = \\\\cos\\\\alpha\\\\cos\\\\beta - \\\\sin\\\\alpha\\\\sin\\\\beta = m,\\n$$\\n$$\\n\\\\cos(\\\\alpha - \\\\beta) = \\\\cos\\\\alpha\\\\cos\\\\beta + \\\\sin\\\\alpha\\\\sin\\\\beta.\\n$$\\n又 $\\\\tan\\\\alpha \\\\tan\\\\beta = \\\\frac{\\\\sin\\\\alpha\\\\sin\\\\beta}{\\\\cos\\\\alpha\\\\cos\\\\beta} = 2$，设 $\\\\cos\\\\alpha\\\\cos\\\\beta = t$，则 $\\\\sin\\\\alpha\\\\sin\\\\beta = 2t$。\\n\\n代入得：$t - 2t = m \\\\Rightarrow -t = m \\\\Rightarrow t = -m$，\\n\\n所以 $\\\\cos(\\\\alpha - \\\\beta) = t + 2t = 3t = -3m$.\",\n      \"comment\": \"\",\n      \"knowledge_points\": [\"三角恒等变换\", \"余弦和差公式\", \"正切与正余弦关系\"],\n      \"difficulty\": 4,\n      \"bbox\": [87, 782, 757, 865],\n      \"region_json\": {\"x1\": 87, \"y1\": 782, \"x2\": 757, \"y2\": 865},\n      \"confidence\": 0.97,\n      \"images\": [],\n      \"page_end\": 2,\n      \"need_review_reason\": \"\",\n      \"raw_explanation\": \"【答案】A\"\n    }\n  ]\n}', 1, NULL, 55798, '2026-05-05 07:26:15.941814', 13, 2, NULL);
