INSERT INTO `tiku_question_image` VALUES (21, 'other', 'exams\\22\\crops\\q161_0.png', 'exams\\22\\pdf\\pages\\page_010.png', '[149, 810, 740, 875]', NULL, '题目中提到“如图”，但图片中未显示实际图形；此处为文字描述的几何关系推导部分，无可见配图。根据规则，若页面中无对应图形图像，则不添加images项。但因题干明确提及“如图”，而当前页未提供图示，需标记潜在缺失。然而，本页图像中确实无图，故images为空数组。', 0, '2026-05-10 14:14:06.194609', NULL, 22, 161);
