-- ----------------------------
-- Table structure for api_task_logs
-- ----------------------------
DROP TABLE IF EXISTS `api_task_logs`;
CREATE TABLE `api_task_logs`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `task_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务ID (格式: tsk_xxxxx)',
  `trace_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '链路追踪ID (格式: trc_xxxxx_yyyy)',
  `problem_id` bigint UNSIGNED NOT NULL COMMENT '问题ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理模式：mode_a / mode_b / mode_c',
  `route_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING' COMMENT '任务状态：PENDING / RUNNING / DONE / FAIL',
  `retry_count` tinyint(1) NULL DEFAULT 0 COMMENT '已重试次数',
  `max_retries` tinyint(1) NULL DEFAULT 3 COMMENT '最大重试次数',
  `next_retry_at` timestamp NULL DEFAULT NULL COMMENT '下一次重试的时间',
  `image_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '图片URL',
  `ali_ocr_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '阿里OCR识别的文本',
  `normalized_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `normalized_text_hash` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `difficulty_flag` tinyint(1) NULL DEFAULT 0 COMMENT '用户标记的难度标记：0-普通，1-困难',
  `request_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '原始请求JSON（用于调试）',
  `vision_extract_json` json NULL,
  `solver_output_json` json NULL,
  `verifier_output_json` json NULL,
  `result_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '最终处理结果JSON',
  `error_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '错误代码（如果失败）',
  `last_error_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '最后的错误代码（来自网关）',
  `error_classification` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '错误分类：network_timeout / network_error / auth_error / model_error / unknown_error',
  `retry_history` json NULL COMMENT '重试历史：[{timestamp, attempt, error_code, error_msg, wait_seconds}, ...]',
  `error_msg` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '错误消息（如果失败）',
  `poll_count` int NULL DEFAULT 0 COMMENT '前端轮询次数',
  `started_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '任务开始时间',
  `finished_at` timestamp NULL DEFAULT NULL COMMENT '任务完成时间',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '记录创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '记录更新时间',
  `task_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '任务类型：vision_mode_a, gemini_analyze, etc.',
  `processing_time_ms` int NULL DEFAULT 0 COMMENT '处理耗时',
  `progress` int NULL DEFAULT 0 COMMENT '进度百分比 (0-100)',
  `request_payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '请求参数',
  `response_payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '响应内容',
  `prompt_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'v2.0',
  `route_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'v2.0',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_trace_id`(`trace_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_mode`(`mode` ASC) USING BTREE,
  INDEX `idx_started_at`(`started_at` ASC) USING BTREE,
  INDEX `idx_finished_at`(`finished_at` ASC) USING BTREE,
  INDEX `idx_retry_count`(`retry_count` ASC) USING BTREE,
  INDEX `idx_next_retry_at`(`next_retry_at` ASC) USING BTREE,
  INDEX `idx_error_classification`(`error_classification` ASC) USING BTREE,
  INDEX `idx_status_retry_count_next_retry_at`(`status` ASC, `retry_count` ASC, `next_retry_at` ASC) USING BTREE,
  INDEX `idx_task_type`(`task_type` ASC) USING BTREE,
  INDEX `idx_status_task_type`(`status` ASC, `task_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1561 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'API异步任务日志表' ROW_FORMAT = Dynamic;

