  `total_requests` int NULL DEFAULT NULL,
  `success_count` int NULL DEFAULT NULL,
  `fail_count` int NULL DEFAULT NULL,
  `hour_bucket` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_type_hour`(`task_type` ASC, `hour_bucket` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

