-- Table structure for gemini_task_queue
-- ----------------------------
DROP TABLE IF EXISTS `gemini_task_queue`;
CREATE TABLE `gemini_task_queue`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `task_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `trace_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `task_type` enum('analyze','process','continue-chat','similar','direct') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `message_payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
