-- Table structure for idempotency_log
-- ----------------------------
DROP TABLE IF EXISTS `idempotency_log`;
CREATE TABLE `idempotency_log`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `request_key` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '请求幂等键',
  `task_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '任务ID',
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '用户ID',
  `checked_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '检查时间',
  `is_duplicate` tinyint(1) NULL DEFAULT 0 COMMENT '是否重复',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `request_key`(`request_key` ASC) USING BTREE,
  INDEX `idx_request_key`(`request_key` ASC) USING BTREE,
