-- Table structure for l5_validation_records
-- ----------------------------
DROP TABLE IF EXISTS `l5_validation_records`;
CREATE TABLE `l5_validation_records`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `task_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
