  `model_a_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'qwen3.5-plus-deep',
  `model_a_result_1` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `model_b_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'doubao2.0-pro',
  `model_b_result_1` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `compare_1_consistent` tinyint(1) NULL DEFAULT NULL,
  `compare_1_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `model_a_result_2` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `model_b_result_2` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `compare_2_consistent` tinyint(1) NULL DEFAULT NULL,
  `compare_2_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
