-- ----------------------------
-- Table structure for learning_records
-- ----------------------------
DROP TABLE IF EXISTS `learning_records`;
CREATE TABLE `learning_records`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `dialogue_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT '对话ID (模式A可为空)',
  `problem_id` bigint UNSIGNED NOT NULL COMMENT '问题ID',
  `mode` enum('A','B','C') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'A' COMMENT '交互模式：A-直接解析，B-苏格拉底互动，C-自由对话',
  `subject` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '学科',
  `topic_tags` json NULL COMMENT '知识点标签',
  `difficulty` tinyint(1) NULL DEFAULT 1 COMMENT '难度等级：1-5级（对应L1-L5）',
  `time_spent` int NULL DEFAULT 0 COMMENT '学习时长（秒）',
  `message_count` int NULL DEFAULT 0 COMMENT '消息交互次数',
  `completion_status` tinyint(1) NULL DEFAULT 0 COMMENT '完成状态：0-未完成，1-已完成',
  `understanding_level` tinyint(1) NULL DEFAULT NULL COMMENT '理解程度：1-5分',
  `learning_outcome` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '学习成果',
  `mistakes_made` json NULL COMMENT '错误记录',
  `improvements` json NULL COMMENT '改进建议',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_dialogue_id`(`dialogue_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  INDEX `idx_subject`(`subject` ASC) USING BTREE,
  INDEX `idx_difficulty`(`difficulty` ASC) USING BTREE,
  INDEX `idx_completion_status`(`completion_status` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE,
  INDEX `idx_learning_records_mode`(`mode` ASC) USING BTREE,
  CONSTRAINT `fk_learning_records_dialogue_id` FOREIGN KEY (`dialogue_id`) REFERENCES `dialogues` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_learning_records_problem_id` FOREIGN KEY (`problem_id`) REFERENCES `problems` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_learning_records_user_id` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '学习记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of learning_records
-- ----------------------------

-- ----------------------------
-- Table structure for llm_audit
-- ----------------------------
DROP TABLE IF EXISTS `llm_audit`;
CREATE TABLE `llm_audit`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `task_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '任务ID',
  `trace_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '追踪ID',
  `model_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'AI模型',
  `mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理模式',
  `prompt_hash` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Prompt哈希',
  `input_tokens` int NULL DEFAULT NULL COMMENT '输入token数',
  `output_tokens` int NULL DEFAULT NULL COMMENT '输出token数',
  `total_tokens` int NULL DEFAULT NULL COMMENT '总token数',
  `gemini_request` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Gemini原始请求',
  `gemini_response` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Gemini原始响应',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '调用状态 (SUCCESS/RATE_LIMIT/TIMEOUT/ERROR)',
  `error_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '错误代码',
  `error_message` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '错误信息',
  `processing_time_ms` int NULL DEFAULT NULL COMMENT '处理耗时(ms)',
  `retry_count` int NULL DEFAULT 0 COMMENT '重试次数',
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '用户ID (可选，日志用)',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_trace_id`(`trace_id` ASC) USING BTREE,
  INDEX `idx_model_name`(`model_name` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 41 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'LLM调用审计日志 (合规和成本)' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of llm_audit
-- ----------------------------

-- ----------------------------
-- Table structure for messages
-- ----------------------------
DROP TABLE IF EXISTS `messages`;
CREATE TABLE `messages`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '消息ID',
  `dialogue_id` bigint UNSIGNED NOT NULL COMMENT '对话ID',
  `sender_type` enum('user','ai') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '发送者类型：user-用户，ai-AI',
  `message_type` enum('text','image','audio','latex') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'text' COMMENT '消息类型',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息内容',
  `latex_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'LaTeX格式内容',
  `audio_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '音频文件URL',
  `audio_duration` int NULL DEFAULT NULL COMMENT '音频时长（秒）',
  `image_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '图片URL',
  `ai_model` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'AI模型（AI消息）',
  `prompt_tokens` int NULL DEFAULT NULL COMMENT '输入token数',
  `completion_tokens` int NULL DEFAULT NULL COMMENT '输出token数',
  `response_time` int NULL DEFAULT NULL COMMENT '响应时间（毫秒）',
  `confidence_score` decimal(5, 2) NULL DEFAULT NULL COMMENT '置信度分数',
  `is_guidance` tinyint(1) NULL DEFAULT 0 COMMENT '是否为引导性问题',
  `parent_message_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT '父消息ID（回复关系）',
  `sequence_number` int NOT NULL COMMENT '消息序号',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '状态：0-删除，1-正常',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `correct_answer` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '选择题正确答案',
  `analysis` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '题目解析内容',
  `question_options` json NULL COMMENT '选择题选项',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_dialogue_id`(`dialogue_id` ASC) USING BTREE,
  INDEX `idx_sender_type`(`sender_type` ASC) USING BTREE,
  INDEX `idx_message_type`(`message_type` ASC) USING BTREE,
  INDEX `idx_parent_message_id`(`parent_message_id` ASC) USING BTREE,
  INDEX `idx_sequence_number`(`sequence_number` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE,
  INDEX `idx_messages_correct_answer`(`correct_answer` ASC) USING BTREE,
  INDEX `idx_messages_dialogue_sender`(`dialogue_id` ASC, `sender_type` ASC) USING BTREE,
  CONSTRAINT `fk_messages_dialogue_id` FOREIGN KEY (`dialogue_id`) REFERENCES `dialogues` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_messages_parent_id` FOREIGN KEY (`parent_message_id`) REFERENCES `messages` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 93 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '对话消息表，支持文本、图片、音频、LaTeX和选择题格式' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of messages
-- ----------------------------

-- ----------------------------
-- Table structure for mode_a_solutions
-- ----------------------------
DROP TABLE IF EXISTS `mode_a_solutions`;
CREATE TABLE `mode_a_solutions`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `task_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务ID',
  `problem_id` bigint UNSIGNED NOT NULL COMMENT '问题ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `final_answer` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '最终答案',
  `summary` json NULL COMMENT '摘要（数组）',
  `steps` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '分步详解（JSON数组）',
  `knowledge_points` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '知识点（JSON数组）',
  `result_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '完整的JSON结果',
  `ai_model_used` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '使用的AI模型：gemini-flash / gemini-pro',
  `is_complex` tinyint(1) NULL DEFAULT 0 COMMENT '是否为复杂问题',
  `schema_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'v1' COMMENT 'Schema版本',
  `confidence_score` decimal(5, 2) NULL DEFAULT NULL COMMENT 'AI置信度评分',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Mode A 解答方案表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mode_a_solutions
-- ----------------------------

-- ----------------------------
-- Table structure for mode_b_flows
-- ----------------------------
DROP TABLE IF EXISTS `mode_b_flows`;
CREATE TABLE `mode_b_flows`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `task_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务ID',
  `problem_id` bigint UNSIGNED NOT NULL COMMENT '问题ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `flow_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '解题思路总标题',
  `steps` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '步骤数组（JSON）',
  `result_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '完整的JSON结果',
  `current_step_index` int NULL DEFAULT 0 COMMENT '当前步骤索引',
  `user_answers` json NULL COMMENT '用户的答案记录',
  `ai_model_used` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '使用的AI模型',
  `is_complex` tinyint(1) NULL DEFAULT 0 COMMENT '是否为复杂问题',
  `schema_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'v1' COMMENT 'Schema版本',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Mode B 流程引导表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mode_b_flows
-- ----------------------------

-- ----------------------------
-- Table structure for mode_b_sessions
-- ----------------------------
DROP TABLE IF EXISTS `mode_b_sessions`;
CREATE TABLE `mode_b_sessions`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` bigint UNSIGNED NOT NULL,
  `flow_id` bigint UNSIGNED NOT NULL,
  `current_step_index` int NULL DEFAULT 0,
  `is_completed` tinyint(1) NULL DEFAULT 0,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '模式B：用户做题会话' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mode_b_sessions
-- ----------------------------

-- ----------------------------
-- Table structure for mode_c_messages
-- ----------------------------
DROP TABLE IF EXISTS `mode_c_messages`;
CREATE TABLE `mode_c_messages`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT,
  `session_id` bigint UNSIGNED NOT NULL,
  `role` enum('user','assistant','system') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `content_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'text' COMMENT 'text/image/voice_url',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_session`(`session_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '模式C：对话记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mode_c_messages
-- ----------------------------

-- ----------------------------
-- Table structure for mode_c_sessions
-- ----------------------------
DROP TABLE IF EXISTS `mode_c_sessions`;
CREATE TABLE `mode_c_sessions`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `task_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务ID',
  `problem_id` bigint UNSIGNED NOT NULL COMMENT '问题ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `initial_question` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '初始问题',
  `conversation` json NULL COMMENT '对话历史（数组）',
  `result_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '完整的JSON结果',
  `message_count` int NULL DEFAULT 0 COMMENT '消息总数',
  `user_message_count` int NULL DEFAULT 0 COMMENT '用户消息数',
  `ai_message_count` int NULL DEFAULT 0 COMMENT 'AI消息数',
  `ai_model_used` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '使用的AI模型：gpt-4 / gemini-pro',
  `is_complex` tinyint(1) NULL DEFAULT 0 COMMENT '是否为复杂问题',
  `schema_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'v1' COMMENT 'Schema版本',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Mode C 自由对话会话表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mode_c_sessions
-- ----------------------------

-- ----------------------------
-- Table structure for monitoring_metrics
-- ----------------------------
DROP TABLE IF EXISTS `monitoring_metrics`;
CREATE TABLE `monitoring_metrics`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `metric_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '指标名称',
  `metric_value` decimal(10, 2) NOT NULL COMMENT '指标值',
  `group_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '指标组 (outbox/task/dlq/etc)',
  `time_window` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '统计窗口 (1h/24h/7d)',
  `recorded_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '记录时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_metric_name`(`metric_name` ASC) USING BTREE,
  INDEX `idx_recorded_at`(`recorded_at` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '监控指标快照' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of monitoring_metrics
-- ----------------------------

-- ----------------------------
-- Table structure for operation_logs
-- ----------------------------
DROP TABLE IF EXISTS `operation_logs`;
CREATE TABLE `operation_logs`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `user_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT '用户ID',
  `operation_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '操作类型',
  `operation_desc` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '操作描述',
  `request_method` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '请求方法',
  `request_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '请求URL',
  `request_params` json NULL COMMENT '请求参数',
  `response_data` json NULL COMMENT '响应数据',
  `ip_address` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `user_agent` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '用户代理',
  `execution_time` int NULL DEFAULT NULL COMMENT '执行时间（毫秒）',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '状态：0-失败，1-成功',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '错误信息',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_operation_type`(`operation_type` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE,
  CONSTRAINT `fk_operation_logs_user_id` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '操作日志表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of operation_logs
-- ----------------------------

-- ----------------------------
-- Table structure for problem_results
-- ----------------------------
DROP TABLE IF EXISTS `problem_results`;
CREATE TABLE `problem_results`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `problem_id` int NOT NULL COMMENT '题目ID',
  `model_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'AI模型名称 (gemini-flash/gemini-pro/gpt-4)',
  `prompt_version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Prompt版本 (pa_20260214)',
  `schema_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'v1' COMMENT 'Schema版本',
  `version_hash` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '三维度版本哈希',
  `normalized_text_hash` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模式 (mode_a/mode_b/mode_c)',
  `result_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理结果 (JSON)',
  `processing_time_ms` int NULL DEFAULT NULL COMMENT '处理耗时',
  `token_usage` int NULL DEFAULT NULL COMMENT 'Token使用数',
  `quality_score` int NULL DEFAULT NULL COMMENT '质量评分 (1-5)',
  `is_cached` tinyint(1) NULL DEFAULT 0 COMMENT '是否来自缓存',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_problem_version`(`problem_id` ASC, `version_hash` ASC, `mode` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  INDEX `idx_version_hash`(`version_hash` ASC) USING BTREE,
  INDEX `idx_mode`(`mode` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE,
  INDEX `idx_norm_hash`(`normalized_text_hash` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 56 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '统一的问题处理结果表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of problem_results
-- ----------------------------

-- ----------------------------
-- Table structure for problems
-- ----------------------------
DROP TABLE IF EXISTS `problems`;
CREATE TABLE `problems`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '问题ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '问题标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '问题内容（OCR识别结果）',
  `pic1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '本地存储第一张图片路径（如：pic/image_1704009600123.jpg）',
  `pic2` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '本地存储第二张图片路径',
  `pic3` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '本地存储第三张图片路径',
  `content_norm` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '规范化后的OCR文本',
  `content_md5` char(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '内容MD5哈希值，用于精确查重',
  `original_image_url1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第一张原始图片URL',
  `original_image_url2` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第二张原始图片URL',
  `original_image_url3` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第三张原始图片URL',
  `corrected_image_url1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第一张百度文档矫正后的图片URL',
  `corrected_image_url2` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第二张百度文档矫正后的图片URL',
  `corrected_image_url3` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '第三张百度文档矫正后的图片URL',
  `subject` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'math' COMMENT '学科：math-数学，physics-物理，chemistry-化学',
  `grade_level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '年级水平',
  `semester` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '题目所属学期: 上学期, 下学期',
  `mode` enum('A','B','C') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'A' COMMENT '交互模式：A-直接解析，B-苏格拉底互动，C-自由对话',
  `difficulty` tinyint(1) NULL DEFAULT 1 COMMENT '难度等级：1-5级（对应L1-L5）',
  `processing_time_sec` int NULL DEFAULT NULL COMMENT '解题总耗时(秒)',
  `topic_tags` json NULL COMMENT '知识点标签',
  `ocr_confidence` decimal(5, 2) NULL DEFAULT NULL COMMENT 'OCR识别置信度',
  `ocr_provider` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'OCR服务提供商',
  `latex_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'LaTeX格式内容',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '状态：0-删除，1-正常',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `gemini_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Gemini 返回的完整 JSON 内容（使用 LONGTEXT 以支持大内容）',
  `gemini_model_version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Gemini 模型版本（如 gemini-2.5-flash）',
  `gemini_request` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '发送给 Gemini 的原始请求 JSON（包含完整 prompt 和参数）',
  `gemini_response` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Gemini 返回的原始响应 JSON（用于后续分析）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_subject`(`subject` ASC) USING BTREE,
  INDEX `idx_difficulty`(`difficulty` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE,
  INDEX `idx_problems_corrected_image_url`(`corrected_image_url1` ASC) USING BTREE,
  INDEX `idx_content_md5`(`content_md5` ASC) USING BTREE,
  INDEX `idx_pic1`(`pic1` ASC) USING BTREE,
  INDEX `idx_problems_mode`(`mode` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1094 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '问题表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of problems
-- ----------------------------

-- ----------------------------
-- Table structure for retry_queue
-- ----------------------------
DROP TABLE IF EXISTS `retry_queue`;
CREATE TABLE `retry_queue`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `task_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务ID',
  `problem_id` bigint UNSIGNED NOT NULL COMMENT '问题ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理模式',
  `retry_count` tinyint(1) NULL DEFAULT 1 COMMENT '重试次数（第几次重试）',
  `max_retries` tinyint(1) NULL DEFAULT 3 COMMENT '最大重试次数',
  `scheduled_at` timestamp NOT NULL COMMENT '计划重试时间',
  `last_error_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '最后的错误代码',
  `error_classification` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '错误分类',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'PENDING' COMMENT '队列状态：PENDING / PROCESSING / DONE / FAILED',
  `processed_at` timestamp NULL DEFAULT NULL COMMENT '处理时间',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_scheduled_at`(`scheduled_at` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  CONSTRAINT `fk_retry_queue_task_id` FOREIGN KEY (`task_id`) REFERENCES `api_task_logs` (`task_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '异步任务重试队列' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of retry_queue
-- ----------------------------

-- ----------------------------
-- Table structure for rollback_logs
-- ----------------------------
DROP TABLE IF EXISTS `rollback_logs`;
CREATE TABLE `rollback_logs`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `reason` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '回滚原因',
  `from_percentage` int NULL DEFAULT NULL COMMENT '回滚前灰度百分比',
  `to_percentage` int NULL DEFAULT NULL COMMENT '回滚后灰度百分比',
  `metric_outbox_sent` decimal(5, 2) NULL DEFAULT NULL COMMENT '触发时Outbox SENT %',
  `metric_completion_rate` decimal(5, 2) NULL DEFAULT NULL COMMENT '触发时任务完成率',
  `metric_dlq_count` int NULL DEFAULT NULL COMMENT '触发时DLQ消息数',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'SUCCESS' COMMENT '回滚状态',
  `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '回滚时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_reason`(`reason` ASC) USING BTREE,
  INDEX `idx_timestamp`(`timestamp` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '灰度部署回滚日志' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of rollback_logs
-- ----------------------------

-- ----------------------------
-- Table structure for system_config
-- ----------------------------
DROP TABLE IF EXISTS `system_config`;
CREATE TABLE `system_config`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置键',
  `value` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置值',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '配置描述',
  `updated_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `key`(`key` ASC) USING BTREE,
  INDEX `idx_key`(`key` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统配置表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of system_config
-- ----------------------------

-- ----------------------------
-- Table structure for system_configs
-- ----------------------------
DROP TABLE IF EXISTS `system_configs`;
CREATE TABLE `system_configs`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `config_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置键',
  `config_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置值',
  `config_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'string' COMMENT '配置类型：string,number,boolean,json',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '配置描述',
  `is_public` tinyint(1) NULL DEFAULT 0 COMMENT '是否公开：0-私有，1-公开',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_config_key`(`config_key` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统配置表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of system_configs
-- ----------------------------

-- ----------------------------
-- Table structure for task_outbox
-- ----------------------------
DROP TABLE IF EXISTS `task_outbox`;
CREATE TABLE `task_outbox`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `task_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任务ID (Snowflake)',
  `trace_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '追踪ID (用于日志关联)',
  `problem_id` int NOT NULL COMMENT '题目ID',
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户ID',
  `mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理模式 (mode_a/mode_b/mode_c)',
  `image_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '题目图片URL',
  `ocr_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'OCR识别结果',
  `request_key` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '请求幂等键 (SHA256)',
  `content_md5` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'OCR内容MD5',
  `model_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '使用的AI模型',
  `prompt_version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Prompt版本',
  `schema_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'v1' COMMENT '输出schema版本',
  `difficulty_flag` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '难度标志',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'NEW' COMMENT '状态: NEW/SENT/ACK (已确认)',
  `retry_count` int NULL DEFAULT 0 COMMENT '投递重试次数',
  `last_error` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '最后一次错误信息',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `sent_at` timestamp NULL DEFAULT NULL COMMENT '消息发送时间',
  `ack_at` timestamp NULL DEFAULT NULL COMMENT '消息确认时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `task_id`(`task_id` ASC) USING BTREE,
  UNIQUE INDEX `trace_id`(`trace_id` ASC) USING BTREE,
  UNIQUE INDEX `request_key`(`request_key` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE,
  INDEX `idx_created_at`(`created_at` ASC) USING BTREE,
  INDEX `idx_sent_at`(`sent_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '本地事务消息表 (Outbox Pattern)' ROW_FORMAT = Dynamic;

